 34→fn position_near_top(window: &tauri::WebviewWindow) {
 35→    let monitor = window
 36→        .current_monitor()
 37→        .ok()
 38→        .flatten()
 39→        .or_else(|| window.primary_monitor().ok().flatten());
 40→
 41→    if let Some(monitor) = monitor {
 42→        let monitor_size = monitor.size();
 43→        let monitor_pos = monitor.position();
 44→
 45→        if let Ok(window_size) = window.outer_size() {
 46→            let x = monitor_pos.x + (monitor_size.width as i32 - window_size.width as i32) / 2;
 47→            let y = monitor_pos.y + (monitor_size.height as i32) / 5;
 48→
 49→            if let Err(e) = window.set_position(tauri::PhysicalPosition::new(x, y)) {
 50→                eprintln!("failed to position window: {e}");
 51→            }
 52→        }
 53→    } else if let Err(e) = window.center() {
 54→        eprintln!("failed to center window: {e}");
 55→    }
 56→}
