 58→fn show_and_focus(window: &tauri::WebviewWindow) {
 59→    let position_pref = window
 60→        .app_handle()
 61→        .try_state::<Mutex<WindowConfig>>()
 62→        .and_then(|state| state.lock().ok().map(|s| s.position_pref.clone()))
 63→        .unwrap_or_else(|| "top-third".to_string());
 64→
 65→    if position_pref == "center" {
 66→        if let Err(e) = window.center() {
 67→            eprintln!("failed to center window: {e}");
 68→        }
 69→    } else {
 70→        position_near_top(window);
 71→    }
 72→
 73→    if let Err(e) = window.show() {
 74→        eprintln!("failed to show window: {e}");
 75→    }
 76→    if let Err(e) = window.set_focus() {
 77→        eprintln!("failed to focus window: {e}");
 78→    }
 79→}
