 81→fn toggle_window(window: &tauri::WebviewWindow) {
 82→    let visible = window.is_visible().unwrap_or(false);
 83→    let focused = window.is_focused().unwrap_or(false);
 84→
 85→    if visible && focused {
 86→        if let Err(e) = window.hide() {
 87→            eprintln!("failed to hide window: {e}");
 88→        }
 89→    } else if visible {
 90→        show_and_focus(window);
 91→    } else {
 92→        show_and_focus(window);
 93→    }
 94→}
