 96→fn detect_content_type(content: &str) -> &'static str {
 97→    let trimmed = content.trim();
 98→
 99→    if trimmed.starts_with("http://") || trimmed.starts_with("https://") {
100→        return "link";
101→    }
102→
103→    if (trimmed.len() == 4 || trimmed.len() == 7 || trimmed.len() == 9)
104→        && trimmed.starts_with('#')
105→        && trimmed[1..].chars().all(|c| c.is_ascii_hexdigit())
106→    {
107→        return "color";
108→    }
109→
110→    if trimmed.starts_with("rgb(")
111→        || trimmed.starts_with("rgba(")
112→        || trimmed.starts_with("hsl(")
113→        || trimmed.starts_with("hsla(")
114→    {
115→        return "color";
116→    }
117→
118→    "text"
119→}
