121→fn start_clipboard_monitor(app_handle: tauri::AppHandle) {
122→    use tauri_plugin_clipboard_manager::ClipboardExt;
123→
124→    std::thread::spawn(move || {
125→        let mut last_text = String::new();
126→
127→        loop {
128→            std::thread::sleep(Duration::from_millis(500));
129→
130→            let text = match app_handle.clipboard().read_text() {
131→                Ok(t) => t,
132→                Err(_) => continue,
133→            };
134→
135→            if text.is_empty() || text == last_text {
136→                continue;
137→            }
138→            last_text = text.clone();
139→
140→            let content_type = detect_content_type(&text);
141→
142→            let elapsed = std::time::SystemTime::now()
143→                .duration_since(std::time::UNIX_EPOCH)
144→                .unwrap_or_default();
145→            let timestamp_ms = elapsed.as_secs() * 1000 + elapsed.subsec_millis() as u64;
146→
147→            let payload = serde_json::json!({
148→                "content": text,
149→                "contentType": content_type,
150→                "timestamp": timestamp_ms,
151→            });
152→
153→            if let Err(e) = app_handle.emit("clipboard-changed", payload) {
154→                eprintln!("failed to emit clipboard-changed: {e}");
155→            }
156→        }
157→    });
158→}
