172→fn detect_file_type(path: &std::path::Path) -> &'static str {
173→    if path.is_dir() {
174→        return "folder";
175→    }
176→
177→    match path
178→        .extension()
179→        .and_then(|e| e.to_str())
180→        .map(|e| e.to_lowercase())
181→        .as_deref()
182→    {
183→        Some(
184→            "ts" | "tsx" | "js" | "jsx" | "rs" | "py" | "rb" | "go" | "java" | "c" | "cpp" | "h"
185→            | "hpp" | "cs" | "swift" | "kt" | "scala" | "sh" | "bash" | "zsh" | "json" | "yaml"
186→            | "yml" | "toml" | "xml" | "html" | "css" | "scss" | "less" | "sql" | "graphql"
187→            | "proto" | "lua" | "r" | "php" | "pl" | "ex" | "exs" | "erl" | "hs" | "ml"
188→            | "vim" | "el" | "clj" | "dart",
189→        ) => "code",
190→        Some("png" | "jpg" | "jpeg" | "gif" | "bmp" | "svg" | "webp" | "ico" | "tiff" | "avif") => {
191→            "image"
192→        }
193→        Some("pdf") => "pdf",
194→        Some("zip" | "tar" | "gz" | "bz2" | "xz" | "7z" | "rar" | "dmg" | "iso") => "archive",
195→        Some("xlsx" | "xls" | "csv" | "numbers" | "ods") => "spreadsheet",
196→        Some("pptx" | "ppt" | "key" | "odp") => "presentation",
197→        Some(
198→            "md" | "txt" | "rtf" | "doc" | "docx" | "pages" | "odt" | "tex" | "log" | "conf"
199→            | "cfg" | "ini" | "env" | "fig",
200→        ) => "document",
201→        _ => "document",
202→    }
203→}
