233→#[tauri::command(async)]
234→fn search_files(query: String, paths: Vec<String>, max_results: usize) -> Vec<FileEntryResult> {
235→    let max = if max_results == 0 { 200 } else { max_results };
236→    let query_lower = query.to_lowercase();
237→    let mut results: Vec<FileEntryResult> = Vec::new();
238→
239→    let search_paths: Vec<String> = if paths.is_empty() {
240→        if let Some(home) = dirs_next::home_dir() {
241→            let home_str = home.to_string_lossy().to_string();
242→            vec![
243→                format!("{home_str}/Documents"),
244→                format!("{home_str}/Downloads"),
245→                format!("{home_str}/Desktop"),
246→                format!("{home_str}/Projects"),
247→            ]
248→        } else {
249→            return results;
250→        }
251→    } else {
252→        paths
253→    };
254→
255→    for search_path in &search_paths {
256→        if results.len() >= max {
257→            break;
258→        }
259→
260→        let walker = WalkDir::new(search_path)
261→            .max_depth(5)
262→            .follow_links(false)
263→            .into_iter()
264→            .filter_entry(|entry| {
265→                let name = entry.file_name().to_string_lossy();
266→                if name.starts_with('.') && entry.depth() > 0 {
267→                    return false;
268→                }
269→                if entry.file_type().is_dir() && is_ignored_dir(&name) {
270→                    return false;
271→                }
272→                true
273→            });
274→
275→        for entry in walker.flatten() {
276→            if results.len() >= max {
277→                break;
278→            }
279→
280→            let name = entry.file_name().to_string_lossy().to_string();
281→
282→            if !query_lower.is_empty() && !name.to_lowercase().contains(&query_lower) {
283→                continue;
284→            }
285→
286→            if entry.depth() == 0 {
287→                continue;
288→            }
289→
290→            let path = entry.path();
291→            let metadata = match entry.metadata() {
292→                Ok(m) => m,
293→                Err(_) => continue,
294→            };
295→
296→            let size = metadata.len();
297→            let modified_at = metadata
298→                .modified()
299→                .ok()
300→                .and_then(|t| t.duration_since(std::time::UNIX_EPOCH).ok())
301→                .map(|d| d.as_millis() as u64)
302→                .unwrap_or(0);
303→
304→            let file_type = detect_file_type(path);
305→            let path_str = path.to_string_lossy().to_string();
306→
307→            let id = format!("fs-{:x}", {
308→                use std::hash::{Hash, Hasher};
309→                let mut h = std::collections::hash_map::DefaultHasher::new();
310→                path_str.hash(&mut h);
311→                h.finish()
312→            });
313→
314→            results.push(FileEntryResult {
315→                id,
316→                name,
317→                path: path_str,
318→                file_type: file_type.to_string(),
319→                size,
320→                modified_at,
321→            });
322→        }
323→    }
324→
325→    results
326→}
