337→#[tauri::command]
338→fn reveal_in_finder(path: String) -> Result<(), String> {
339→    let p = std::path::Path::new(&path);
340→    if !is_path_within_home(p) {
341→        return Err(format!("path not allowed: {path}"));
342→    }
343→
344→    #[cfg(target_os = "macos")]
