353→            return Err(format!("failed to reveal {path}: {stderr}"));
354→        }
355→        return Ok(());
356→    }
357→
358→    #[cfg(target_os = "windows")]
359→    {
360→        let output = std::process::Command::new("explorer")
361→            .arg(format!("/select,{}", &path))
362→            .output()
363→            .map_err(|e| format!("failed to reveal {path}: {e}"))?;
364→        if !output.status.success() {
365→            let stderr = String::from_utf8_lossy(&output.stderr);
366→            return Err(format!("failed to reveal {path}: {stderr}"));
367→        }
368→        return Ok(());
369→    }
370→
371→    #[cfg(target_os = "linux")]
372→    {
373→        let parent = std::path::Path::new(&path)
374→            .parent()
375→            .map(|p| p.to_string_lossy().to_string())
376→            .unwrap_or_else(|| path.clone());
377→        let output = std::process::Command::new("xdg-open")
378→            .arg(&parent)
379→            .output()
380→            .map_err(|e| format!("failed to reveal: {e}"))?;
381→        if !output.status.success() {
382→            let stderr = String::from_utf8_lossy(&output.stderr);
383→            return Err(format!("failed to reveal: {stderr}"));
384→        }
385→        return Ok(());
386→    }
387→
388→    #[allow(unreachable_code)]
389→    Err("unsupported platform".to_string())
390→}
