409→fn scan_app_dir(dir: &std::path::Path, depth: usize) -> Vec<std::path::PathBuf> {
410→    let mut apps = Vec::new();
411→    let Ok(entries) = std::fs::read_dir(dir) else {
412→        return apps;
413→    };
414→
415→    for entry in entries.flatten() {
416→        let path = entry.path();
417→        if path.extension().map_or(false, |e| e == "app") {
418→            apps.push(path);
419→        } else if depth > 0 && path.is_dir() {
420→            let name = path.file_name().unwrap_or_default().to_string_lossy();
421→            if !name.starts_with('.') {
422→                apps.extend(scan_app_dir(&path, depth - 1));
423→            }
424→        }
425→    }
426→    apps
427→}
