434→fn display_name_from_plist(dict: &plist::Dictionary) -> Option<String> {
435→    dict.get("CFBundleDisplayName")
436→        .or_else(|| dict.get("CFBundleName"))
437→        .and_then(|v| v.as_string())
438→        .map(|s| s.to_string())
