441→fn extract_png_from_icns(icns_data: &[u8]) -> Option<Vec<u8>> {
442→    if icns_data.len() < 8 || &icns_data[0..4] != b"icns" {
443→        return None;
444→    }
445→
446→    let total_len = u32::from_be_bytes(icns_data[4..8].try_into().ok()?) as usize;
447→    let total_len = total_len.min(icns_data.len());
448→
449→    let preferred: &[&[u8; 4]] = &[
450→        b"icp5", b"icp6", b"icp4", b"ic07",
451→    ];
452→
453→    let mut offset = 8;
454→    let mut entries: Vec<(&[u8], &[u8])> = Vec::new();
455→
456→    while offset + 8 <= total_len {
457→        let type_code = &icns_data[offset..offset + 4];
458→        let entry_len = u32::from_be_bytes(icns_data[offset + 4..offset + 8].try_into().ok()?) as usize;
459→        if entry_len < 8 || offset + entry_len > total_len {
460→            break;
461→        }
462→        let data = &icns_data[offset + 8..offset + entry_len];
463→        entries.push((type_code, data));
464→        offset += entry_len;
465→    }
466→
467→    for pref in preferred {
468→        for (type_code, data) in &entries {
469→            if *type_code == pref.as_slice() && data.starts_with(&[0x89, 0x50, 0x4E, 0x47]) {
470→                return Some(data.to_vec());
471→            }
472→        }
473→    }
474→
475→    let max_fallback_size = 200_000;
476→    for (_, data) in &entries {
477→        if data.starts_with(&[0x89, 0x50, 0x4E, 0x47]) && data.len() <= max_fallback_size {
478→            return Some(data.to_vec());
479→        }
480→    }
481→
482→    None
483→}
