485→fn extract_app_icon(app_path: &std::path::Path, dict: &plist::Dictionary) -> Option<String> {
486→    let icon_name = dict
487→        .get("CFBundleIconFile")
488→        .and_then(|v| v.as_string())
489→        .unwrap_or("AppIcon");
490→
491→    let icon_filename = if icon_name.ends_with(".icns") {
492→        icon_name.to_string()
493→    } else {
494→        format!("{icon_name}.icns")
495→    };
496→
497→    let icns_path = app_path.join("Contents/Resources").join(&icon_filename);
498→    let icns_data = std::fs::read(&icns_path).ok()?;
499→    let png_data = extract_png_from_icns(&icns_data)?;
500→
501→    Some(format!(
502→        "data:image/png;base64,{}",
503→        base64::engine::general_purpose::STANDARD.encode(&png_data)
504→    ))
505→}
