507→fn build_app_list() -> Vec<AppEntry> {
508→    let mut apps = Vec::new();
509→    let mut seen_paths = std::collections::HashSet::new();
510→
511→    let mut dirs = vec![std::path::PathBuf::from("/Applications")];
512→    if let Some(home) = dirs_next::home_dir() {
513→        dirs.push(home.join("Applications"));
514→    }
515→
516→    for dir in &dirs {
517→        for app_path in scan_app_dir(dir, 1) {
518→            let path_str = app_path.to_string_lossy().to_string();
519→            if !seen_paths.insert(path_str.clone()) {
520→                continue;
521→            }
522→
523→            let file_stem = app_path
524→                .file_stem()
525→                .map(|s| s.to_string_lossy().to_string())
526→                .unwrap_or_default();
527→
528→            let plist_dict = read_info_plist(&app_path);
529→            let name = plist_dict
530→                .as_ref()
531→                .and_then(display_name_from_plist)
532→                .unwrap_or_else(|| file_stem.clone());
533→            let icon = plist_dict
534→                .as_ref()
535→                .and_then(|dict| extract_app_icon(&app_path, dict));
536→
537→            let id = format!("app-{:x}", {
538→                use std::hash::{Hash, Hasher};
539→                let mut h = std::collections::hash_map::DefaultHasher::new();
540→                path_str.hash(&mut h);
541→                h.finish()
542→            });
543→
544→            apps.push(AppEntry {
545→                id,
546→                name,
547→                path: path_str,
548→                icon,
549→            });
550→        }
551→    }
552→
553→    apps.sort_by(|a, b| a.name.to_lowercase().cmp(&b.name.to_lowercase()));
554→    apps
555→}
