557→#[tauri::command(async)]
558→fn discover_applications(
559→    state: tauri::State<'_, Mutex<AppCache>>,
560→    force_refresh: bool,
561→) -> Vec<AppEntry> {
562→    if !force_refresh {
563→        if let Ok(cache) = state.lock() {
564→            if let Some(ref apps) = cache.apps {
565→                return apps.clone();
566→            }
567→        }
568→    }
569→
570→    let apps = build_app_list();
571→
572→    if let Ok(mut cache) = state.lock() {
573→        cache.apps = Some(apps.clone());
574→    }
575→
576→    apps
577→}
