579→fn is_valid_app_path(path: &std::path::Path) -> bool {
580→    let canonical = match path.canonicalize() {
581→        Ok(p) => p,
582→        Err(_) => return false,
583→    };
584→
585→    if canonical.extension().map_or(true, |e| e != "app") {
586→        return false;
587→    }
588→
589→    let mut allowed_dirs = vec![std::path::PathBuf::from("/Applications")];
590→    if let Some(home) = dirs_next::home_dir() {
591→        allowed_dirs.push(home.join("Applications"));
592→    }
593→
594→    for dir in &allowed_dirs {
595→        if let Ok(canonical_dir) = dir.canonicalize() {
596→            if canonical.starts_with(&canonical_dir) {
597→                return true;
598→            }
599→        }
600→    }
601→    false
602→}
