627→#[tauri::command]
628→fn set_window_position_pref(
629→    state: tauri::State<'_, Mutex<WindowConfig>>,
630→    position: String,
631→) -> Result<(), String> {
632→    match position.as_str() {
633→        "center" | "top-third" => {
634→            if let Ok(mut config) = state.lock() {
635→                config.position_pref = position;
636→                Ok(())
637→            } else {
638→                Err("failed to acquire config lock".to_string())
639→            }
