776→#[cfg_attr(mobile, tauri::mobile_entry_point)]
777→pub fn run() {
778→    tauri::Builder::default()
779→        .plugin(tauri_plugin_clipboard_manager::init())
780→        .plugin(tauri_plugin_shell::init())
781→        .plugin(tauri_plugin_autostart::init(MacosLauncher::LaunchAgent, None))
782→        .plugin(
783→            tauri_plugin_sql::Builder::default()
784→                .add_migrations("sqlite:raycast_clone.db", db_migrations())
785→                .build(),
786→        )
787→        .manage(Mutex::new(WindowConfig::default()))
788→        .manage(Mutex::new(AppCache::default()))
789→        .invoke_handler(tauri::generate_handler![
790→            set_window_position_pref,
791→            search_files,
792→            open_file,
793→            reveal_in_finder,
794→            move_to_trash,
795→            discover_applications,
796→            launch_application
797→        ])
798→        .setup(|app| {
799→            #[cfg(desktop)]
800→            {
801→                let shortcut = Shortcut::new(Some(Modifiers::ALT), Code::Space);
802→                let window = app
803→                    .get_webview_window("main")
804→                    .expect("main window not found");
805→
806→                let window_for_blur = window.clone();
807→                window.on_window_event(move |event| {
808→                    if let tauri::WindowEvent::Focused(false) = event {
809→                        if let Err(e) = window_for_blur.hide() {
810→                            eprintln!("failed to hide on blur: {e}");
811→                        }
812→                    }
813→                });
814→
815→                #[cfg(target_os = "macos")]
816→                {
817→                    use window_vibrancy::{apply_vibrancy, NSVisualEffectMaterial};
818→                    if let Err(e) =
819→                        apply_vibrancy(&window, NSVisualEffectMaterial::HudWindow, None, None)
820→                    {
821→                        eprintln!("failed to apply vibrancy: {e}");
822→                    }
823→                }
824→
825→                position_near_top(&window);
826→
827→                start_clipboard_monitor(app.handle().clone());
828→
829→                let window_for_shortcut = window.clone();
830→                app.handle().plugin(
831→                    tauri_plugin_global_shortcut::Builder::new()
832→                        .with_handler(move |_app, scut, event| {
833→                            if scut == &shortcut && event.state() == ShortcutState::Pressed {
834→                                toggle_window(&window_for_shortcut);
835→                            }
836→                        })
837→                        .build(),
838→                )?;
839→
840→                app.global_shortcut().register(shortcut)?;
841→
842→                let show_item =
843→                    MenuItem::with_id(app, "show", "Show Raycast", true, None::<&str>)?;
844→                let clipboard_item =
845→                    MenuItem::with_id(app, "clipboard", "Clipboard History", true, None::<&str>)?;
846→                let snippets_item =
847→                    MenuItem::with_id(app, "snippets", "Snippets", true, None::<&str>)?;
848→                let settings_item =
849→                    MenuItem::with_id(app, "settings", "Settings", true, None::<&str>)?;
850→                let check_updates_item = MenuItem::with_id(
851→                    app,
852→                    "check-updates",
853→                    "Check for Updates",
854→                    true,
855→                    None::<&str>,
856→                )?;
857→                let about_item =
858→                    MenuItem::with_id(app, "about", "About Raycast Clone", true, None::<&str>)?;
859→                let quit_item = MenuItem::with_id(app, "quit", "Quit", true, None::<&str>)?;
860→
861→                let menu = Menu::with_items(
862→                    app,
863→                    &[
864→                        &show_item,
865→                        &PredefinedMenuItem::separator(app)?,
866→                        &clipboard_item,
867→                        &snippets_item,
868→                        &settings_item,
869→                        &PredefinedMenuItem::separator(app)?,
870→                        &check_updates_item,
871→                        &about_item,
872→                        &quit_item,
873→                    ],
874→                )?;
875→
876→                let window_for_menu = window.clone();
877→                let window_for_tray = window.clone();
878→
879→                TrayIconBuilder::new()
880→                    .icon(tauri::image::Image::from_bytes(include_bytes!(
881→                        "../icons/tray-icon@2x.png"
882→                    ))?)
883→                    .icon_as_template(true)
884→                    .tooltip("Raycast Clone")
885→                    .menu(&menu)
886→                    .show_menu_on_left_click(false)
887→                    .on_menu_event(move |app, event| match event.id().as_ref() {
888→                        "show" => {
889→                            show_and_focus(&window_for_menu);
890→                        }
891→                        "clipboard" | "snippets" | "settings" | "about" | "check-updates" => {
892→                            show_and_focus(&window_for_menu);
893→                            if let Err(e) =
894→                                app.emit("tray-navigate", event.id().as_ref().to_string())
895→                            {
896→                                eprintln!("failed to emit tray-navigate: {e}");
897→                            }
898→                        }
899→                        "quit" => {
900→                            app.exit(0);
901→                        }
902→                        _ => {}
903→                    })
904→                    .on_tray_icon_event(move |_tray, event| {
905→                        if let TrayIconEvent::Click {
906→                            button: MouseButton::Left,
907→                            button_state: MouseButtonState::Up,
908→                            ..
909→                        } = event
910→                        {
911→                            toggle_window(&window_for_tray);
912→                        }
913→                    })
914→                    .build(app)?;
915→            }
916→
917→            Ok(())
918→        })
919→        .run(tauri::generate_context!())
920→        .expect("error while running tauri application");
921→}
