 57→  fontSize: 'default',
 58→};
 59→
 60→function isGeneralSettings(value: unknown): value is GeneralSettings {
 61→  if (!isRecord(value)) return false;
 62→  return (
 63→    typeof value.appearance === 'string' &&
 64→    typeof value.windowWidth === 'string' &&
 65→    typeof value.showRecentApps === 'boolean' &&
 66→    typeof value.showDock === 'boolean' &&
 67→    typeof value.fontSize === 'string' &&
 68→    typeof value.windowPosition === 'string'
 69→  );
 70→}
 71→
 72→function parseSettings(raw: string | null): GeneralSettings | null {
 73→  if (!raw) return null;
 74→  try {
 75→    const parsed: unknown = JSON.parse(raw);
 76→    return isGeneralSettings(parsed) ? parsed : null;
 77→  } catch {
 78→    return null;
 79→  }
 80→}
 81→
 82→function parseExtensionStates(
 83→  raw: string | null,
 84→): Record<string, boolean> | null {
 85→  if (!raw) return null;
 86→  try {
 87→    const parsed: unknown = JSON.parse(raw);
 88→    return isBooleanRecord(parsed) ? parsed : null;
 89→  } catch {
 90→    return null;
 91→  }
 92→}
