435→function ExtensionsTab({
436→  extensions,
437→  onToggle,
438→  query,
439→}: {
440→  extensions: ExtensionEntry[];
441→  onToggle: (id: string) => void;
442→  query: string;
443→}) {
444→  const filtered = useMemo(() => {
445→    if (!query) return extensions;
446→    const lower = query.toLowerCase();
447→    return extensions.filter(
448→      ext =>
449→        ext.name.toLowerCase().includes(lower) ||
450→        ext.description.toLowerCase().includes(lower) ||
451→        ext.author.toLowerCase().includes(lower),
452→    );
453→  }, [
454→    extensions,
455→    query,
456→  ]);
457→
458→  const raycastExts = filtered.filter(ext => ext.author === 'Raycast');
459→  const communityExts = filtered.filter(ext => ext.author !== 'Raycast');
460→
461→  return (
462→    <div className="settings-view__extensions">
463→      {filtered.length === 0 ? (
464→        <EmptyState
465→          icon={<SearchEmptyIcon />}
466→          title="No Extensions Found"
467→          description="Try a different search term"
468→        />
469→      ) : (
470→        <>
471→          {raycastExts.length > 0 && (
472→            <div className="settings-section">
473→              <div className="settings-section__title">Built-in</div>
474→              {raycastExts.map(ext => (
475→                <ExtensionRow
476→                  key={ext.id}
477→                  ext={ext}
478→                  onToggle={onToggle}
479→                  showAuthor={false}
480→                />
481→              ))}
482→            </div>
483→          )}
484→          {communityExts.length > 0 && (
485→            <div className="settings-section">
486→              <div className="settings-section__title">Community</div>
487→              {communityExts.map(ext => (
488→                <ExtensionRow
489→                  key={ext.id}
490→                  ext={ext}
491→                  onToggle={onToggle}
492→                  showAuthor
493→                />
494→              ))}
495→            </div>
496→          )}
497→        </>
498→      )}
499→    </div>
500→  );
501→}
